export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-hd'
  | (string & {});

// Provider-specific settings passed via providerOptions.pixelart
export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g., "512x512", "1024x1024").
   * Overrides the standard `size` parameter when provided.
   */
  size?: string;

  /**
