### 9. `packages/pixelart/src/pixelart-image-model.ts`

The core image model. Key design decisions:
- Implements `ImageModelV3` from `@ai-sdk/provider`
- Uses `postJsonToApi` + `createJsonResponseHandler` (no file downloads needed — API returns base64)
- Provider-specific settings are read from `providerOptions.pixelart` via `parseProviderOptions` with a Zod schema
- Standard `size` param from call options is used if `providerOptions.pixelart.size` is not provided
- `aspectRatio`, `seed`, `files`, `mask` are unsupported — produce warnings
- API request body: `{ model, prompt, n, size, style, pixel_density }`
- API response: `{ images: [{ b64_json: string }], model: string, created: number }`
- Returns base64 strings (not Uint8Array) in the `images` array

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';

// Zod schema for provider-specific options
const pixelArtImageSettingsSchema = z.object({
  size: z.string().nullish(),
  style: z.enum(['pixel', 'retro', '8bit']).nullish(),
  pixelDensity: z.number().nullish(),
});

// Config injected by the provider factory
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Zod response schema
const pixelArtResponseSchema = z.object({
  images: z.array(z.object({ b64_json: z.string() })),
  model: z.string(),
  created: z.number(),
});

// Error handler
const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: z.object({ error: z.object({ message: z.string() }) }),
  errorToMessage: data => data.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal } = options;
    const warnings: SharedV3Warning[] = [];

    // Parse provider-specific options
    const settings = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported-setting', setting: 'aspectRatio' });
    }
    if (seed != null) {
      warnings.push({ type: 'unsupported-setting', setting: 'seed' });
    }
    if (options.files != null && options.files.length > 0) {
      warnings.push({ type: 'unsupported-setting', setting: 'image' });
    }
    if (options.mask != null) {
      warnings.push({ type: 'unsupported-setting', setting: 'mask' });
    }

    // Build request body
    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      size: settings?.size ?? size,
    };
    if (settings?.style != null) requestBody.style = settings.style;
    if (settings?.pixelDensity != null) requestBody.pixel_density = settings.pixelDensity;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: response.model,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created,
        },
      },
    };
  }
}
```

