### 10. `packages/pixelart/src/pixelart-provider.ts`

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import { loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Defaults to PIXELART_API_KEY environment variable.
   */
  apiKey?: string;
  /**
   * Base URL for API calls. Defaults to https://api.pixelart.ai/v1.
   */
  baseURL?: string;
  /**
   * Custom headers to include in all requests.
   */
  headers?: Record<string, string>;
  /**
   * Custom fetch implementation (e.g., for testing or middleware).
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates an image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? DEFAULT_BASE_URL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();
```

---

### 11. `packages/pixelart/src/index.ts`

```typescript
export type { PixelArtProvider, PixelArtProviderSettings } from './pixelart-provider';
export { createPixelArt, pixelart } from './pixelart-provider';
export type { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';
export { VERSION } from './version';
```

---

## Implementation Order

1. `package.json`
2. `tsconfig.json`
3. `tsconfig.build.json`
4. `tsup.config.ts`
5. `vitest.node.config.js`
6. `vitest.edge.config.js`
7. `src/version.ts`
8. `src/pixelart-image-settings.ts`
9. `src/pixelart-image-model.ts`
10. `src/pixelart-provider.ts`
11. `src/index.ts`

---

## Verification

```bash
# 1. Install dependencies (from repo root)
pnpm install

# 2. Type-check just this package
cd packages/pixelart && pnpm type-check

# 3. Full type check across the entire monorepo
cd <repo-root> && pnpm type-check:full

# 4. Build the package
cd packages/pixelart && pnpm build

# 5. Verify dist/ contains index.js, index.mjs, index.d.ts
ls packages/pixelart/dist/
```

The package deliberately does NOT need to be added to the root `tsconfig.json` references or `pnpm` workspace config, as the workspace is auto-discovered via `packages/*` glob and the tsconfig references are only needed for cross-package type checking during development (which `pnpm type-check:full` handles automatically).

