import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  jsonSchema,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import type { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';

// Internal parsed provider options (nullish fields to match JSON Schema optional)
interface PixelArtImageSettingsParsed {
  size?: string | null;
  style?: 'pixel' | 'retro' | '8bit' | null;
  pixelDensity?: number | null;
}

// Response shape returned by the PixelArt API
interface PixelArtApiResponse {
  images: Array<{ b64_json: string }>;
  model: string;
  created: number;
}

// Error shape returned by the PixelArt API
interface PixelArtApiError {
  error: { message: string };
}

// JSON Schema for the API response — used by createJsonResponseHandler for type-safe parsing
const pixelArtResponseSchema = jsonSchema<PixelArtApiResponse>({
  type: 'object',
  properties: {
    images: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          b64_json: { type: 'string' },
        },
        required: ['b64_json'],
      },
    },
    model: { type: 'string' },
    created: { type: 'number' },
  },
  required: ['images', 'model', 'created'],
});

// JSON Schema for API errors
const pixelArtErrorSchema = jsonSchema<PixelArtApiError>({
  type: 'object',
  properties: {
    error: {
      type: 'object',
      properties: {
        message: { type: 'string' },
      },
      required: ['message'],
    },
  },
  required: ['error'],
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: data => data.error.message,
});

// Config injected by the provider factory (not directly user-facing)
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: SharedV3Warning[] = [];

    // Extract provider-specific settings from providerOptions.pixelart
    const settings = (providerOptions?.pixelart ??
      {}) as PixelArtImageSettingsParsed &
      Omit<PixelArtImageSettings, keyof PixelArtImageSettingsParsed>;

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use size instead.',
      });
    }
    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support seed-based reproducibility.',
      });
    }
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support image-to-image generation.',
      });
    }
    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting with masks.',
      });
    }

    // Build the JSON request body.
    // Provider settings.size takes precedence over the standard SDK size parameter.
    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      size: settings.size ?? size,
    };

    if (settings.style != null) {
      requestBody.style = settings.style;
    }
    if (settings.pixelDensity != null) {
      requestBody.pixel_density = settings.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: response.model,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created,
        },
      },
    };
  }
}

